// NORMALIZAR — BEST EFFORT, ajustar tras la primera corrida (ver el output real de Apify).
// Saca teléfono de campos estructurados o, si no, de la bio por regex. Gate SMA por bio/área.
const rubros = ['plomero','gasista','electricista','cerrajero','carpintero','pintor','albanil','cabanas','jardinero','limpieza'];
const items = $input.all();
const rows = [];
const seen = new Set();
function toE164(raw) {
  let d = (raw || '').replace(/\D/g, '');
  if (!d) return null;
  if (d.startsWith('54')) { d = d.slice(2); }
  d = d.replace(/^0/, '').replace(/^9/, '');
  if (d.length < 10) return null;
  return '+549' + d.slice(-10);
}
items.forEach((it, i) => {
  const rubro = rubros[i] || '';
  const arr = Array.isArray(it.json) ? it.json : [it.json];
  for (const p of arr) {
    if (!p) continue;
    const bio = (p.biography || p.bio || '') + '';
    const name = p.fullName || p.full_name || p.username || '';
    // teléfono: campo estructurado de cuenta business, o regex de la bio
    let phone = toE164(p.public_phone_number || p.businessPhoneNumber || p.phone || '');
    if (!phone) {
      const m = bio.match(/(?:\+?54\s?9?)?[\s\-]?(?:0?2(?:972|944|99)|11)[\s\-]?\d{3}[\s\-]?\d{4}/);
      if (m) phone = toE164(m[0]);
    }
    if (!phone) continue;
    // gate SMA: bio/nombre menciona SMA o el teléfono es de área local (2972/2944)
    const localHint = /san mart|sma|8370|chapelco|2972|2944/i.test(bio + ' ' + name) || /^\+549(2972|2944)/.test(phone);
    if (!localHint) continue;
    if (seen.has(phone)) continue;
    seen.add(phone);
    rows.push({
      name, phone, rubro, ciudad: 'san-martin', source: 'instagram',
      rating_externo: null, reviews_externo: null,
      address: null, notas: p.username ? ('ig: @' + p.username + ' (verificar)') : 'ig (verificar)',
    });
  }
});
return [{ json: { rows, count: rows.length } }];
